import{_ as e,o as n,c as a,ak as p}from"./chunks/framework.DwHlt8HN.js";const u=JSON.parse('{"title":"KubeSphere","description":"","frontmatter":{},"headers":[],"relativePath":"devops/kubesphere/index.md","filePath":"devops/kubesphere/index.md","lastUpdated":1774320699000}'),r={name:"devops/kubesphere/index.md"};function l(t,s,i,b,h,c){return n(),a("div",null,[...s[0]||(s[0]=[p(`<h1 id="kubesphere" tabindex="-1">KubeSphere <a class="header-anchor" href="#kubesphere" aria-label="Permalink to “KubeSphere”">​</a></h1><p>企业级容器平台的国产之光，也是 Kubernetes 生态中最接地气的可视化管理层。</p><p>很多人对 KubeSphere 的第一印象是「一个好看的 K8s 管理界面」。但如果你真正用起来，会发现它解决的远不止可视化问题——多租户隔离、内置 DevOps 流水线、应用商店、日志收集、监控告警、服务网格，这些在 K8s 原生环境中需要分别配置的功能，在 KubeSphere 里被整合成了统一的操作体验。</p><p>这篇文章系列覆盖 KubeSphere 的定位与架构、多租户体系、核心功能（DevOps、服务网格、日志监控）、以及运维管理。无论你是企业用户，还是想了解云原生平台的产品设计思路，都能从中获得有价值的内容。</p><h2 id="模块速览" tabindex="-1">模块速览 <a class="header-anchor" href="#模块速览" aria-label="Permalink to “模块速览”">​</a></h2><p>KubeSphere 的定位介于原生 K8s 和 OpenShift 之间——比原生更易用，比 OpenShift 更开放。</p><table tabindex="0"><thead><tr><th>方向</th><th>篇数</th><th>核心目标</th></tr></thead><tbody><tr><td><a href="/devops/kubesphere/overview">KubeSphere 基础</a></td><td>5 篇</td><td>定位对比、架构设计、多租户体系、安装部署</td></tr><tr><td><a href="/devops/kubesphere/app-store">KubeSphere 核心功能</a></td><td>7 篇</td><td>应用商店、流水线、告警通知、日志审计、服务网格、监控</td></tr><tr><td><a href="/devops/kubesphere/pipeline-syntax">KubeSphere DevOps</a></td><td>5 篇</td><td>Jenkinsfile 语法、制品仓库、自动构建、部署策略、GitOps</td></tr><tr><td><a href="/devops/kubesphere/node-management">KubeSphere 运维管理</a></td><td>6 篇</td><td>节点管理、存储网络、集群升级、权限管理、故障排查</td></tr></tbody></table><h2 id="学习路径建议" tabindex="-1">学习路径建议 <a class="header-anchor" href="#学习路径建议" aria-label="Permalink to “学习路径建议”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>第一阶段：入门与部署（2-3 天）</span></span>
<span class="line"><span>→ 理解 KubeSphere 的定位：与 OpenShift、Rancher 的区别</span></span>
<span class="line"><span>→ 搭建 All-in-One 环境（体验版）</span></span>
<span class="line"><span>→ 多节点部署（生产环境）</span></span>
<span class="line"><span>→ 多租户体系：Workspace、Namespace、Project 的层级关系</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第二阶段：DevOps 实战（1 周）</span></span>
<span class="line"><span>→ 流水线配置：Jenkinsfile in SCM vs 图形化编辑</span></span>
<span class="line"><span>→ 二进制制品仓库与镜像仓库集成</span></span>
<span class="line"><span>→ 自动化构建与镜像推送流程</span></span>
<span class="line"><span>→ 蓝绿部署与滚动更新配置</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第三阶段：运维管理（1 周）</span></span>
<span class="line"><span>→ 节点管理与污点配置</span></span>
<span class="line"><span>→ 存储类型与持久卷管理</span></span>
<span class="line"><span>→ 集群升级与版本管理</span></span>
<span class="line"><span>→ 基于角色的权限配置（RBAC）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第四阶段：高级功能（1 周）</span></span>
<span class="line"><span>→ 基于 Istio 的服务网格可视化</span></span>
<span class="line"><span>→ 自定义监控与告警规则配置</span></span>
<span class="line"><span>→ FluentBit 日志收集架构</span></span>
<span class="line"><span>→ GitOps 工作流集成</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br></div></div><h2 id="kubesphere-和-rancher-怎么选" tabindex="-1">KubeSphere 和 Rancher 怎么选？ <a class="header-anchor" href="#kubesphere-和-rancher-怎么选" aria-label="Permalink to “KubeSphere 和 Rancher 怎么选？”">​</a></h2><p>这是很多人都会问的问题。两个都是 K8s 多集群管理平台，但定位有所不同：</p><p><strong>Rancher</strong> 更像一个「K8s 管理平台」——它的核心价值是简化 K8s 集群的创建、管理、升级，降低 K8s 的使用门槛。Rancher 2.x 基于 RKE（ Rancher Kubernetes Engine），3.x 开始支持 K3s 和 RKE2。</p><p><strong>KubeSphere</strong> 更像一个「企业级应用平台」——它在 K8s 之上，封装了一层面向业务的功能：DevOps 流水线、应用商店、服务网格、多租户计费……如果你想在一个平台里完成从代码到上线到监控的全流程，KubeSphere 更适合。</p><p>简单来说：<strong>管理 K8s 集群选 Rancher，在 K8s 上跑应用选 KubeSphere。</strong></p><h2 id="面试的核心逻辑" tabindex="-1">面试的核心逻辑 <a class="header-anchor" href="#面试的核心逻辑" aria-label="Permalink to “面试的核心逻辑”">​</a></h2><p>KubeSphere 作为一个平台类产品，面试通常不会考你「会不会点按钮」，而是考察你对平台架构和工程实践的理解：</p><ol><li><strong>多租户设计</strong>：KubeSphere 的 Workspace、Namespace、Project 三层模型是怎么实现租户隔离的？不同层级的权限如何控制？</li><li><strong>DevOps 集成</strong>：KubeSphere 的流水线是怎么跑起来的？ Jenkins 是怎么被集成进来的？</li><li><strong>可观测性</strong>：KubeSphere 的监控、日志、告警是怎么实现的？背后依赖了哪些组件（Prometheus、Elasticsearch、FluentBit）？</li><li><strong>运维能力</strong>：集群升级怎么做？多节点环境下的网络和存储怎么规划？</li></ol><blockquote><p>&quot;KubeSphere 的面试，本质上考的是你对 K8s 生态的掌握程度。KubeSphere 只是入口，背后连着的仍然是 Pod、Service、PV、RBAC 这些 K8s 原生概念。&quot;</p></blockquote>`,18)])])}const o=e(r,[["render",l]]);export{u as __pageData,o as default};
